<?php
declare(strict_types=1);

function ensure_email_preference(int $contactId,string $source='crm'):array{$q=db()->prepare('SELECT * FROM contact_email_preferences WHERE contact_id=?');$q->execute([$contactId]);$p=$q->fetch();if(!$p){$token=bin2hex(random_bytes(32));db()->prepare("INSERT INTO contact_email_preferences(contact_id,status,consent_source,consent_at,unsubscribe_token) VALUES(?,'subscribed',?,NOW(),?)")->execute([$contactId,$source,$token]);$q->execute([$contactId]);$p=$q->fetch();}return $p;}
function sns_signature_valid(array $message):bool{$url=(string)($message['SigningCertURL']??'');$parts=parse_url($url);if(($parts['scheme']??'')!=='https'||!preg_match('/(^|\.)amazonaws\.com$/i',(string)($parts['host']??'')))return false;$cert=@file_get_contents($url);if(!$cert)return false;$order=$message['Type']==='Notification'?['Message','MessageId','Subject','Timestamp','TopicArn','Type']:['Message','MessageId','SubscribeURL','Timestamp','Token','TopicArn','Type'];$string='';foreach($order as $key)if(isset($message[$key]))$string.=$key."\n".$message[$key]."\n";$signature=base64_decode((string)($message['Signature']??''),true);return $signature!==false&&openssl_verify($string,$signature,$cert,OPENSSL_ALGO_SHA1)===1;}

if($path==='/webhooks/ses'&&$method==='POST'){$raw=(string)file_get_contents('php://input');$sns=json_decode($raw,true)?:[];if(!sns_signature_valid($sns)){http_response_code(403);exit('Invalid SNS signature');}if(($sns['Type']??'')==='SubscriptionConfirmation'){$url=(string)$sns['SubscribeURL'];$parts=parse_url($url);if(($parts['scheme']??'')==='https'&&preg_match('/(^|\.)amazonaws\.com$/i',(string)($parts['host']??'')))@file_get_contents($url);http_response_code(204);exit;}$event=json_decode((string)($sns['Message']??''),true)?:[];$type=strtolower((string)($event['eventType']??$event['notificationType']??'unknown'));$messageId=(string)($event['mail']['messageId']??'');$recipients=[];if($type==='bounce')foreach($event['bounce']['bouncedRecipients']??[] as $r)$recipients[]=$r['emailAddress']??'';elseif($type==='complaint')foreach($event['complaint']['complainedRecipients']??[] as $r)$recipients[]=$r['emailAddress']??'';else $recipients=(array)($event['mail']['destination']??[]);foreach(array_unique(array_filter(array_map(fn($x)=>strtolower(trim((string)$x)),$recipients))) as $email){db()->prepare('INSERT INTO email_delivery_events(provider,provider_message_id,event_type,recipient,payload_json,occurred_at) VALUES(\'ses\',?,?,?,?,NOW())')->execute([$messageId,$type,$email,json_encode($event)]);if(in_array($type,['bounce','complaint'],true))db()->prepare('INSERT INTO email_suppressions(email,reason,source) VALUES(?,?,\'ses\') ON DUPLICATE KEY UPDATE reason=VALUES(reason),source=VALUES(source),released_at=NULL,released_by=NULL')->execute([$email,$type]);}$status=['delivery'=>'delivered','bounce'=>'bounced','complaint'=>'complained'][$type]??null;if($status&&$messageId!=='')db()->prepare('UPDATE email_messages SET delivery_status=? WHERE provider_message_id=?')->execute([$status,$messageId]);http_response_code(204);exit;}

if(preg_match('#^/email/unsubscribe/([a-f0-9]{64})$#',$path,$m)){$q=db()->prepare('SELECT p.*,c.email,c.first_name FROM contact_email_preferences p JOIN contacts c ON c.id=p.contact_id WHERE p.unsubscribe_token=?');$q->execute([$m[1]]);$p=$q->fetch();if(!$p){http_response_code(404);exit('Preference link not found');}if($method==='POST'){verify_csrf();$status=post('status')==='subscribed'?'subscribed':'unsubscribed';db()->prepare('UPDATE contact_email_preferences SET status=?,unsubscribed_at=IF(?=\'unsubscribed\',NOW(),NULL),consent_source=IF(?=\'subscribed\',\'preference_center\',consent_source),consent_at=IF(?=\'subscribed\',NOW(),consent_at) WHERE contact_id=?')->execute([$status,$status,$status,$status,$p['contact_id']]);if($status==='unsubscribed')db()->prepare("INSERT INTO email_suppressions(email,reason,source) VALUES(?,'unsubscribe','preference_center') ON DUPLICATE KEY UPDATE reason='unsubscribe',source='preference_center',released_at=NULL")->execute([strtolower($p['email'])]);else db()->prepare("UPDATE email_suppressions SET released_at=NOW() WHERE email=? AND reason='unsubscribe'")->execute([strtolower($p['email'])]);flash('success','Email preferences updated.');redirect('/email/unsubscribe/'.$m[1]);}layout('Email preferences',function()use($p){?><div class="card login"><h1>Email preferences</h1><p>Hello <?=e($p['first_name'])?>. Choose whether you want non-transactional email. Booking confirmations, security notices, and requested documents may still be sent.</p><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><button name="status" value="subscribed">Subscribe</button><button class="danger" name="status" value="unsubscribed">Unsubscribe</button></form><p class="muted">Current status: <?=e($p['status'])?></p></div><?php });exit;}

if(preg_match('#^/contacts/(\d+)/email-preferences$#',$path,$m)){$c=contact_row((int)$m[1]);require_permission('communications.edit');$p=ensure_email_preference((int)$c['id']);if($method==='POST'){verify_csrf();$status=in_array(post('status'),['subscribed','unsubscribed','transactional_only'],true)?post('status'):'transactional_only';db()->prepare('UPDATE contact_email_preferences SET status=?,consent_source=?,consent_at=IF(?=\'subscribed\',NOW(),consent_at),unsubscribed_at=IF(?=\'unsubscribed\',NOW(),NULL),updated_by=? WHERE contact_id=?')->execute([$status,trim((string)post('consent_source')),$status,$status,user()['id'],$c['id']]);audit('update','contact_email_preference',(int)$c['id'],['status'=>$status]);flash('success','Email preference updated.');redirect('/contacts/'.$c['id'].'/email-preferences');}layout('Contact email preferences',function()use($c,$p){?><h1><?=e($c['first_name'].' '.$c['last_name'])?> email preferences</h1><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Status<select name="status"><option value="subscribed" <?=$p['status']==='subscribed'?'selected':''?>>Subscribed</option><option value="transactional_only" <?=$p['status']==='transactional_only'?'selected':''?>>Transactional only</option><option value="unsubscribed" <?=$p['status']==='unsubscribed'?'selected':''?>>Unsubscribed</option></select></label><label>Consent source<input name="consent_source" value="<?=e($p['consent_source'])?>" placeholder="Form, event, verbal consent…"></label><button>Save preference</button></form><?php });exit;}

if($path==='/admin/email-compliance'){require_login();if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}if($method==='POST'){verify_csrf();db()->prepare('UPDATE email_suppressions SET released_at=NOW(),released_by=? WHERE id=?')->execute([user()['id'],(int)post('suppression_id')]);audit('release','email_suppression',(int)post('suppression_id'));redirect('/admin/email-compliance');}$rows=db()->query('SELECT * FROM email_suppressions WHERE released_at IS NULL ORDER BY created_at DESC LIMIT 1000')->fetchAll();$events=db()->query('SELECT event_type,COUNT(*) total,MAX(created_at) latest FROM email_delivery_events GROUP BY event_type ORDER BY total DESC')->fetchAll();layout('Email compliance',function()use($rows,$events){?><h1>Email compliance & deliverability</h1><div class="grid"><?php foreach($events as $e):?><div class="card"><div class="metric"><?=$e['total']?></div><?=e(ucfirst($e['event_type']))?><br><span class="muted">Latest <?=e($e['latest'])?></span></div><?php endforeach?></div><div class="card"><h2>Active suppression list</h2><table><thead><tr><th>Email</th><th>Reason</th><th>Source</th><th>Added</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['email'])?></td><td><?=e($r['reason'])?></td><td><?=e($r['source'])?></td><td><?=e($r['created_at'])?></td><td><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="suppression_id" value="<?=$r['id']?>"><button class="compact secondary" onclick="return confirm('Release this suppression?')">Release</button></form></td></tr><?php endforeach?></tbody></table></div><div class="card"><h2>Amazon SES event endpoint</h2><code><?=e(rtrim((string)config('url'),'/').'/webhooks/ses')?></code><p class="muted">Subscribe this HTTPS endpoint to an SNS topic receiving SES delivery, bounce, and complaint events.</p></div><?php });exit;}
